// Robust EDA builder for n8n — returns profiles_summary + sampleRows
const rows = items.map(i => i.json || {});
if (rows.length === 0) {
  return [{ json: { error: "Empty dataset - no rows produced by CSV node" } }];
}

// sanitize header keys (remove BOM + trim)
const sanitizeKey = k => String(k || "").replace(/^\uFEFF/, "").trim();
const rawCols = Object.keys(rows[0]);
const cols = rawCols.map(sanitizeKey);

// rebuild rows with sanitized keys
const normalized = rows.map(r => {
  const out = {};
  rawCols.forEach((rk, idx) => { out[cols[idx]] = r[rk]; });
  return out;
});

const isNumberLike = v => v !== null && v !== undefined && v !== "" && !isNaN(Number(String(v).replace(/,/g, "")));
const median = arr => { const a = arr.slice().sort((x,y)=>x-y); if(!a.length) return null; const m=Math.floor(a.length/2); return a.length%2 ? a[m] : (a[m-1]+a[m])/2; };

const profiles = cols.map(col => {
  const valsRaw = normalized.map(r => {
    const v = r[col]; if (v === undefined || v === null || String(v).trim()==="") return null; return String(v).trim();
  }).filter(v => v !== null);
  const missingCount = normalized.length - valsRaw.length;
  const uniqueCount = new Set(valsRaw).size;
  const numericVals = valsRaw.filter(isNumberLike).map(v => Number(String(v).replace(/,/g,"")));
  const inferredType = (numericVals.length / Math.max(1, valsRaw.length)) > 0.7 ? "numeric" : "categorical";
  const p = { columnName: col, totalCount: normalized.length, missingCount, missingPct: Number(((missingCount/normalized.length)*100).toFixed(2)), uniqueCount, sampleValues: valsRaw.slice(0,5), inferredType };

  if (inferredType === "numeric") {
    const n = numericVals.length;
    const sum = n ? numericVals.reduce((a,b)=>a+b,0) : 0;
    const mean = n ? sum / n : null;
    const med = median(numericVals);
    const variance = n ? numericVals.reduce((s,x)=>s+Math.pow(x-mean,2),0)/n : null;
    const std = variance !== null ? Math.sqrt(variance) : null;
    p.stats = { count: n, sum: n ? Number(sum.toFixed(4)) : null, mean: mean !== null ? Number(mean.toFixed(4)) : null, median: med !== null ? Number(med.toFixed(4)) : null, std: std !== null ? Number(std.toFixed(4)) : null, min: n ? Math.min(...numericVals) : null, max: n ? Math.max(...numericVals) : null };
  } else {
    const freq = {};
    for (const v of valsRaw) freq[v] = (freq[v] || 0) + 1;
    p.topValues = Object.entries(freq).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([val,count])=>({val,count}));
  }
  return p;
});

// trimmed summary to send to Gemini (keeps payload small)
const profiles_summary = profiles.map(p => ({ columnName: p.columnName, inferredType: p.inferredType, missingPct: p.missingPct, uniqueCount: p.uniqueCount, stats: p.stats ? p.stats : null, topValues: p.topValues ? p.topValues : null }));

return [{ json: { datasetName: $json.datasetName || $json.fileName || "Uploaded Dataset", rowCount: normalized.length, columnCount: cols.length, profiles, profiles_summary, sampleRows: normalized.slice(0,5) } }];

// Try common Gemini locations
const raw =
  $json.text ||
  ($json.candidates && $json.candidates[0] && $json.candidates[0].content && $json.candidates[0].content.parts && $json.candidates[0].content.parts[0] && $json.candidates[0].content.parts[0].text) ||
  ($json.content && $json.content.parts && $json.content.parts[0] && $json.content.parts[0].text) ||
  ($json.outputText) ||
  "";

// Fallback: if entire item has an 'output' field
if(!raw && $json.output && typeof $json.output === 'string') raw = $json.output;

if(!raw) {
  return [{ json: { error: "No text found in Gemini output", debug: $json } }];
}

// remove triple backticks ```html or ```
let html = String(raw).trim();
html = html.replace(/^\s*```(?:\s*html)?\s*/i, '').replace(/\s*```\s*$/i, '');
html = html.replace(/^\s*~~~(?:\s*html)?\s*/i, '').replace(/\s*~~~\s*$/i, '');

// ensure starts with <!doctype or <html>
const idx = html.toLowerCase().indexOf('<!doctype');
if(idx > 0) html = html.slice(idx);
if(html.toLowerCase().indexOf('<!doctype') === -1 && html.toLowerCase().indexOf('<html') === -1) {
  // not full html — wrap simple body
  html = "<!doctype html><html><head><meta charset='utf-8'><title>EDA Report</title></head><body>" + html + "</body></html>";
}

// ensure page-break CSS exists (inject small CSS if missing)
if(html.indexOf('@page') === -1) {
  const inject = `<style>@page{size:A4;margin:20mm}.page-break{page-break-after:always}</style>`;
  html = html.replace(/<head>/i, '<head>' + inject);
}

// Return html_report and binary data (base64)
return [{
  json: { html_report: html },
  binary: {
    data: {
      data: Buffer.from(html, 'utf8').toString('base64'),
      mimeType: 'text/html',
      fileName: 'report.html'
    }
  }
}];

// Your form trigger node name
const FORM_NODE = "On form submission";

let original = {};
try {
  original = $items(FORM_NODE)[0].json;
} catch (e) {
  original = {};
}

const current = $json || {};

const user_email =
  current.user_email ||
  original.user_email ||
  null;

return [{
  json: { 
    ...current, 
    user_email 
  },
  binary: $binary
}];

// "items" is an array of rows from Extract from CSV
const rows = items.map(i => i.json);

// Make a single big JSON string
const dataJson = JSON.stringify(rows);

// Return a single item with one field: data_json
return [
  {
    json: {
      data_json: dataJson
    }
  }
];
